import{_ as d,o as r,c as a,a2 as s}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"Boss战斗机制","description":"","frontmatter":{},"headers":[],"relativePath":"guide/boss.md","filePath":"guide/boss.md","lastUpdated":null}'),o={name:"guide/boss.md"};function e(h,t,l,n,i,b){return r(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="boss战斗机制" tabindex="-1">Boss战斗机制 <a class="header-anchor" href="#boss战斗机制" aria-label="Permalink to &quot;Boss战斗机制&quot;">​</a></h1><p>修仙服务器对Boss进行了全面强化——动态缩放、专属弹幕、魔改技能，让每场Boss战都充满挑战。</p><hr><h2 id="boss动态缩放" tabindex="-1">Boss动态缩放 <a class="header-anchor" href="#boss动态缩放" aria-label="Permalink to &quot;Boss动态缩放&quot;">​</a></h2><p>所有Boss根据挑战者的修仙等级动态调整强度：</p><ul><li><strong>启用</strong>：✅</li><li><strong>每级HP加成</strong>：+5%</li><li><strong>每级伤害加成</strong>：+5%</li><li><strong>Boss喊话间隔</strong>：10秒</li><li>修仙等级越高，Boss越强！</li></ul><h3 id="缩放公式" tabindex="-1">缩放公式 <a class="header-anchor" href="#缩放公式" aria-label="Permalink to &quot;缩放公式&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>实际HP  = Boss基础HP  × (1 + 修士修仙等级 × 0.05)</span></span>
<span class="line"><span>实际伤害 = Boss基础伤害 × (1 + 修士修仙等级 × 0.05)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="受缩放影响的boss" tabindex="-1">受缩放影响的Boss <a class="header-anchor" href="#受缩放影响的boss" aria-label="Permalink to &quot;受缩放影响的Boss&quot;">​</a></h3><p>以下Boss会随修士等级动态缩放：</p><table tabindex="0"><thead><tr><th>Boss ID</th><th>Boss名称</th></tr></thead><tbody><tr><td>4</td><td>克苏鲁之眼</td></tr><tr><td>13</td><td>世界吞噬者</td></tr><tr><td>35</td><td>骷髅王</td></tr><tr><td>50</td><td>史莱姆王</td></tr><tr><td>113</td><td>双子魔眼</td></tr><tr><td>125</td><td>世纪之花</td></tr><tr><td>127</td><td>石巨人</td></tr><tr><td>134</td><td>猪鲨公爵</td></tr><tr><td>245</td><td>光之女皇</td></tr><tr><td>262</td><td>拜月教徒</td></tr><tr><td>370</td><td>月亮领主</td></tr><tr><td>398</td><td>月总加强</td></tr><tr><td>439</td><td>霜月Boss</td></tr><tr><td>636</td><td>撒旦军团Boss</td></tr></tbody></table><hr><h2 id="boss弹幕系统" tabindex="-1">Boss弹幕系统 <a class="header-anchor" href="#boss弹幕系统" aria-label="Permalink to &quot;Boss弹幕系统&quot;">​</a></h2><p>每个Boss学会了修仙者的灵气弹幕技能：</p><table tabindex="0"><thead><tr><th>Boss ID</th><th>弹幕间隔</th><th>弹幕图案</th><th>弹幕数</th><th>速度</th><th>伤害倍率</th></tr></thead><tbody><tr><td>4 (克眼)</td><td>15秒</td><td>灵气弹幕、追踪灵气</td><td>8</td><td>6.0</td><td>×0.6</td></tr><tr><td>13 (世吞)</td><td>12秒</td><td>暗影领域、灵气弹幕</td><td>6</td><td>4.0</td><td>×0.5</td></tr><tr><td>35 (骷髅王)</td><td>14秒</td><td>螺旋剑阵、追踪灵气</td><td>6</td><td>7.0</td><td>×0.7</td></tr><tr><td>113 (双子魔眼)</td><td>10秒</td><td>流星坠落、追踪灵气、暗影领域</td><td>10</td><td>8.0</td><td>×0.5</td></tr><tr><td>125 (世纪之花)</td><td>10秒</td><td>追踪灵气、雷暴</td><td>6</td><td>9.0</td><td>×0.6</td></tr><tr><td>134 (猪鲨)</td><td>8秒</td><td>流星坠落、灵气弹幕</td><td>12</td><td>6.0</td><td>×0.4</td></tr><tr><td>127 (石巨人)</td><td>9秒</td><td>螺旋剑阵、追踪灵气、雷暴</td><td>8</td><td>8.0</td><td>×0.6</td></tr><tr><td>262 (拜月教徒)</td><td>11秒</td><td>暗影领域、灵气弹幕</td><td>10</td><td>7.0</td><td>×0.7</td></tr><tr><td>245 (光之女皇)</td><td>13秒</td><td>流星坠落、雷暴</td><td>8</td><td>6.0</td><td>×0.6</td></tr><tr><td>370 (月总)</td><td>7秒</td><td>螺旋剑阵、追踪灵气、雷暴、流星坠落</td><td>10</td><td>11.0</td><td>×0.5</td></tr><tr><td>636 (撒旦军团)</td><td>8秒</td><td>螺旋剑阵、追踪灵气</td><td>12</td><td>10.0</td><td>×0.6</td></tr><tr><td>439 (霜月Boss)</td><td>9秒</td><td>暗影领域、雷暴</td><td>8</td><td>8.0</td><td>×0.7</td></tr><tr><td>398 (月总加强)</td><td><strong>6秒</strong></td><td><strong>全部6种图案</strong></td><td>14</td><td>12.0</td><td>×0.45</td></tr></tbody></table><h3 id="弹幕图案说明" tabindex="-1">弹幕图案说明 <a class="header-anchor" href="#弹幕图案说明" aria-label="Permalink to &quot;弹幕图案说明&quot;">​</a></h3><table tabindex="0"><thead><tr><th>图案</th><th>名称</th><th>描述</th></tr></thead><tbody><tr><td>QiBarrage</td><td>灵气弹幕</td><td>扇形散射灵气弹</td></tr><tr><td>HomingQi</td><td>追踪灵气</td><td>追踪玩家的灵气弹</td></tr><tr><td>SpiralSwords</td><td>螺旋剑阵</td><td>旋转排列的剑气</td></tr><tr><td>FallingStars</td><td>流星坠落</td><td>从天而降的流星</td></tr><tr><td>LightningStorm</td><td>雷暴</td><td>闪电轰击</td></tr><tr><td>ShadowZone</td><td>暗影领域</td><td>区域性暗影伤害</td></tr></tbody></table><hr><h2 id="boss魔改技能" tabindex="-1">Boss魔改技能 <a class="header-anchor" href="#boss魔改技能" aria-label="Permalink to &quot;Boss魔改技能&quot;">​</a></h2><p>部分Boss拥有专属魔改技能，在血量降低到一定程度时触发：</p><h3 id="克苏鲁之眼-id-4" tabindex="-1">克苏鲁之眼（ID 4） <a class="header-anchor" href="#克苏鲁之眼-id-4" aria-label="Permalink to &quot;克苏鲁之眼（ID 4）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>技能</th><th>触发血量</th><th>冷却</th><th>弹幕数</th><th>速度</th><th>伤害倍率</th></tr></thead><tbody><tr><td>追踪灵气</td><td>≤100%</td><td>8秒</td><td>5</td><td>7.0</td><td>×0.5</td></tr><tr><td>灵气弹幕</td><td>≤55%</td><td>12秒</td><td>10</td><td>8.0</td><td>×0.6</td></tr></tbody></table><h3 id="史莱姆王-id-50" tabindex="-1">史莱姆王（ID 50） <a class="header-anchor" href="#史莱姆王-id-50" aria-label="Permalink to &quot;史莱姆王（ID 50）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>技能</th><th>触发血量</th><th>冷却</th><th>额外效果</th></tr></thead><tbody><tr><td>流星坠落</td><td>≤80%</td><td>10秒</td><td>弹幕8个,速度7.0</td></tr><tr><td>召唤小怪</td><td>≤45%</td><td>18秒</td><td>召唤3个史莱姆</td></tr></tbody></table><blockquote><p>命中Debuff：25%概率造成 <strong>4秒着火了！</strong></p></blockquote><h3 id="骷髅王-id-35" tabindex="-1">骷髅王（ID 35） <a class="header-anchor" href="#骷髅王-id-35" aria-label="Permalink to &quot;骷髅王（ID 35）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>技能</th><th>触发血量</th><th>冷却</th><th>弹幕数</th><th>速度</th><th>伤害倍率</th></tr></thead><tbody><tr><td>螺旋剑阵</td><td>≤100%</td><td>9秒</td><td>6</td><td>8.0</td><td>×0.65</td></tr><tr><td>雷暴</td><td>≤50%</td><td>14秒</td><td>7</td><td>9.0</td><td>×0.7</td></tr></tbody></table><h3 id="双子魔眼-id-113" tabindex="-1">双子魔眼（ID 113） <a class="header-anchor" href="#双子魔眼-id-113" aria-label="Permalink to &quot;双子魔眼（ID 113）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>技能</th><th>触发血量</th><th>冷却</th><th>弹幕数</th><th>伤害倍率</th></tr></thead><tbody><tr><td>暗影领域</td><td>≤90%</td><td>10秒</td><td>7</td><td>×0.55</td></tr><tr><td>流星坠落</td><td>≤50%</td><td>8秒</td><td>12</td><td>×0.55</td></tr></tbody></table><blockquote><p>命中Debuff：20%概率造成 <strong>5秒困惑</strong></p></blockquote><h3 id="月亮领主加强-id-398-⚡终极boss" tabindex="-1">月亮领主加强（ID 398）⚡终极Boss <a class="header-anchor" href="#月亮领主加强-id-398-⚡终极boss" aria-label="Permalink to &quot;月亮领主加强（ID 398）⚡终极Boss&quot;">​</a></h3><table tabindex="0"><thead><tr><th>技能</th><th>触发血量</th><th>冷却</th><th>弹幕数</th><th>速度</th><th>伤害倍率</th></tr></thead><tbody><tr><td>灵气弹幕</td><td>≤100%</td><td>6秒</td><td>14</td><td>10.0</td><td>×0.45</td></tr><tr><td>螺旋剑阵</td><td>≤70%</td><td>7秒</td><td>12</td><td>12.0</td><td>×0.5</td></tr><tr><td>雷暴</td><td>≤40%</td><td>6秒</td><td>10</td><td>12.0</td><td>×0.55</td></tr></tbody></table><blockquote><p>命中Debuff：18%概率造成 <strong>4秒霜火</strong></p></blockquote><hr><h2 id="怪物吸血机制" tabindex="-1">怪物吸血机制 <a class="header-anchor" href="#怪物吸血机制" aria-label="Permalink to &quot;怪物吸血机制&quot;">​</a></h2><ul><li><strong>普通怪物吸血</strong>：伤害的 <strong>20%</strong> 转化为生命</li><li><strong>Boss吸血</strong>：伤害的 <strong>35%</strong> 转化为生命</li><li><strong>吸血上限</strong>：基础生命的 <strong>×1.5</strong></li></ul><blockquote><p>💡 输出越高，怪物回血越快！建议优先击杀小怪。</p></blockquote><hr><h2 id="修士减伤" tabindex="-1">修士减伤 <a class="header-anchor" href="#修士减伤" aria-label="Permalink to &quot;修士减伤&quot;">​</a></h2><p>启用修士减伤机制，减少来自怪物的伤害，让修仙者在面对高强度Boss时更具生存力。</p><hr><h2 id="boss喊话" tabindex="-1">Boss喊话 <a class="header-anchor" href="#boss喊话" aria-label="Permalink to &quot;Boss喊话&quot;">​</a></h2><p>Boss在战斗不同阶段会喊话嘲讽，增加沉浸感。详情参见 <a href="/guide/yulu.html">修仙语录</a> 章节。</p><hr><h2 id="boss战策略" tabindex="-1">Boss战策略 <a class="header-anchor" href="#boss战策略" aria-label="Permalink to &quot;Boss战策略&quot;">​</a></h2><h3 id="通用建议" tabindex="-1">通用建议 <a class="header-anchor" href="#通用建议" aria-label="Permalink to &quot;通用建议&quot;">​</a></h3><ol><li><strong>准备充足药水</strong> — Boss血量动态缩放，战斗时间可能很长</li><li><strong>带好治疗丹/恢复丹</strong> — 关键时刻保命</li><li><strong>注意弹幕躲避</strong> — Boss弹幕速度最高12.0（月总加强），走位很关键</li><li><strong>优先击杀小怪</strong> — 怪物有吸血，小怪不清理Boss会持续回复</li><li><strong>组队作战</strong> — 带新人还能赚功德</li></ol><h3 id="各boss注意点" tabindex="-1">各Boss注意点 <a class="header-anchor" href="#各boss注意点" aria-label="Permalink to &quot;各Boss注意点&quot;">​</a></h3><ul><li><strong>克苏鲁之眼</strong>：55%血以下弹幕数量翻倍，需提高警惕</li><li><strong>史莱姆王</strong>：45%血召唤小怪，需快速清场</li><li><strong>骷髅王</strong>：50%血触发雷暴，注意躲避</li><li><strong>双子魔眼</strong>：二阶段12弹幕的流星坠落极难躲避</li><li><strong>月总加强</strong>：6秒间隔的全图案弹幕+雷暴，全服最强Boss</li></ul><hr><h2 id="小boss动态缩放列表" tabindex="-1">小Boss动态缩放列表 <a class="header-anchor" href="#小boss动态缩放列表" aria-label="Permalink to &quot;小Boss动态缩放列表&quot;">​</a></h2><p>以下16个小Boss也受修仙等级动态缩放影响（每级HP/伤害+5%）：</p><table tabindex="0"><thead><tr><th>Boss ID</th><th>名称</th></tr></thead><tbody><tr><td>540-544</td><td>史莱姆系列（5种）</td></tr><tr><td>325-329</td><td>万圣树妖系列（5种）</td></tr><tr><td>422</td><td>暗黑魔法师</td></tr><tr><td>493</td><td>荷兰飞盗船</td></tr><tr><td>507</td><td>双足翼龙</td></tr><tr><td>517</td><td>食人魔</td></tr><tr><td>521</td><td>黑暗魔法师（变体）</td></tr><tr><td>534</td><td>火星飞碟</td></tr></tbody></table><hr><h2 id="boss战斗数据速查" tabindex="-1">Boss战斗数据速查 <a class="header-anchor" href="#boss战斗数据速查" aria-label="Permalink to &quot;Boss战斗数据速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Boss</th><th>ID</th><th>弹幕间隔</th><th>弹幕数</th><th>速度</th><th>魔改技能数</th><th>命中Debuff</th></tr></thead><tbody><tr><td>克苏鲁之眼</td><td>4</td><td>15秒</td><td>8</td><td>6.0</td><td>2</td><td>无</td></tr><tr><td>史莱姆王</td><td>50</td><td>—</td><td>—</td><td>—</td><td>2</td><td>着火了! 4秒(25%)</td></tr><tr><td>世界吞噬者</td><td>13</td><td>12秒</td><td>6</td><td>4.0</td><td>0</td><td>无</td></tr><tr><td>骷髅王</td><td>35</td><td>14秒</td><td>6</td><td>7.0</td><td>2</td><td>无</td></tr><tr><td>血肉墙</td><td>113</td><td>10秒</td><td>10</td><td>8.0</td><td>2</td><td>困惑 5秒(20%)</td></tr><tr><td>双子魔眼</td><td>125</td><td>10秒</td><td>6</td><td>9.0</td><td>0</td><td>无</td></tr><tr><td>世纪之花</td><td>262</td><td>11秒</td><td>10</td><td>7.0</td><td>0</td><td>无</td></tr><tr><td>石巨人</td><td>245</td><td>13秒</td><td>8</td><td>6.0</td><td>0</td><td>无</td></tr><tr><td>猪鲨公爵</td><td>370</td><td>7秒</td><td>10</td><td>11.0</td><td>0</td><td>无</td></tr><tr><td>光之女皇</td><td>636</td><td>8秒</td><td>12</td><td>10.0</td><td>0</td><td>无</td></tr><tr><td>拜月教教徒</td><td>439</td><td>9秒</td><td>8</td><td>8.0</td><td>0</td><td>无</td></tr><tr><td>月亮领主加强</td><td>398</td><td><strong>6秒</strong></td><td><strong>14</strong></td><td><strong>12.0</strong></td><td><strong>3</strong></td><td>霜火 4秒(18%)</td></tr></tbody></table>`,56)])])}const g=d(o,[["render",e]]);export{c as __pageData,g as default};
